import React, { useEffect, useState } from 'react';

// Custom hook to debounce updates by a specified delay time
export function useDebounce<T extends Record<string, unknown>>(callback: (value: T) => void, memoKey?: string): [T, () => void] {
  const [debouncedValue, setDebouncedValue] = useState<T | null>(null);
  const [debounceTime, setDebounceTime] = useState<number>(0);

  useEffect(() => {
    if (debouncedValue) {
      setTimeout(() => callback(debouncedValue), debounceTime);
    }
  }, [callback, debounceTime]);

  return [debouncedValue, () => {
    if (!debouncedValue) return;
    setDebounceTime(Math.max(0, Math.min(memoKey ? memoKey : 'initial'), debounceTime));
    setDebouncedValue(null);
  }];
}

// Search TextInput component using the useDebounce hook
export function SearchTextInput({ placeholder = '', value: initialValue }: { placeholder?: string; value: T | null }) {
  const [debouncedValue, apply] = useDebounce((value) => {
    if (typeof value === 'string') {
      setDebouncedValue(value);
    } else {
      setDebouncedValue(null);
    }
  }, 500);

  return (
    <View style={{ padding: 12 }}>
      <TextInput
        placeholder={placeholder}
        value={initialValue || ''}
        onChangeText={(text) => apply(text)}
        onEndEditing={() => apply(null)}
        keyboardType="default"
        maxLength={30}
        onSubmitEditing={apply}
        accessibilityHint={debouncedValue ? 'Debounced search result' : null}
      />
    </View>
  );
}

