import { FlatList, LayoutSizeProvider, StyleSheet } from 'react-native';

const MemoizedFlatList = React.memo((props) => {
  const [windowSize, setWindowSize] = useState({ width: 0 });

  useEffect(() => {
    // Set layout size based on window size
    const newSize = Math.min(windowSize.width * 2, 100);
    LayoutSizeProvider.setLayoutSize(newSize);
  }, [windowSize]);

  return (
    <LayoutSizeProvider layoutSize={windowSize}>
      <FlatList
        data={props.data}
        keyExtractor={(item) => item.key}
        renderItem={({ item }) => (
          <View style={{ flex: 1, alignItems: 'center' }}>
            {item?.text || 'Item'}
          </View>
        )}
        contentContainerStrategy="wrap"
      />
    </LayoutSizeProvider>
  );
});

